var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"작전기록 녹음.","JPN":"作戦記録、録音。","ENG":"Operation log.","TWN":"作戰紀錄錄音。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"시간…… 알 수 없음.","JPN":"時間……不明。","ENG":"Time... Unknown.","TWN":"無法得知……時間。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"위치…… 알 수 없음.","JPN":"場所……不明。","ENG":"Location... Unknown.","TWN":"無法得知……位置。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"오늘도 지원이 오지 않는다.","JPN":"まだ応援はこない。","ENG":"No support came today as well.","TWN":"今天也沒有支援抵達。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만…….","JPN":"だが……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"지원이 오기 전까지, 대원들을 지켜야 한다.","JPN":"応援が来るまで、隊員たちを守らなければ。","ENG":"I must protect my squad members until the day support comes.","TWN":"在支援抵達之前，我必須守護隊員們。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"작전기록 녹음.","JPN":"作戦記録、録音。","ENG":"Operation log.","TWN":"作戰紀錄錄音。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"71회째로 방주의 동결을 해제하려 시도했으나, 실패했다.","JPN":"71回目、箱舟の凍結を解こうとしたが失敗した。","ENG":"Attempt 71 of undoing the Ark's stasis, failed.","TWN":"這是第71次嘗試解凍方舟，再次失敗。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……물자 보급은, 더 이상 연기할 수 없는 상황이다.","JPN":"……物資の補給は、これ以上先延ばしにはできない状況だ。","ENG":"...Supplies are running low. I cannot delay it any longer.","TWN":"……物資補給已經無法再耽延下去。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"다행히 이 일대에는 방치된 함선들이 많다.","JPN":"幸い、ここ一帯には放置されている艦船が多い。","ENG":"Luckily, there are many abandoned ships nearby.","TWN":"幸好這附近有許多擱置的艦船。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"눈보라가 약해지는 대로, 함선들을 순회하면서 물자 확보에 나설 계획이다.","JPN":"吹雪の勢いがおさまり次第、艦船を巡回しつつ物資の確保をしようと思う。","ENG":"When the blizzard dies down, I will plan a route to secure supplies from the ships.","TWN":"等暴風雪減弱後，我會去巡視看看裡面有沒有物資。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"첫 번째 함선에선 유의미한 물품을 건지지 못했다.","JPN":"最初の艦船では役立つものは発見できなかった。","ENG":"The first ship did not have any useful supplies.","TWN":"在第一艘艦船中沒有尋獲適合的物資。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"다행히 인근에 있던 두 번째 함선에서 전투식량을 소량 발견할 수 있었다.","JPN":"幸運にも近くにあった二隻目の艦船からは戦闘食糧を少量発見することができた。","ENG":"However, I was able to find some combat rations from the second ship in proximity.","TWN":"幸好在附近第二艘艦船中有發現少量的戰鬥物資。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"여기 온 뒤 며칠이 지났는지 정확한 일자는 알 수 없으나……","JPN":"ここに来てから何日経ったのか正確にはわからないが……","ENG":"Although it is unclear how much time has passed since I arrived here...","TWN":"來到這裡後，不知道已經經過幾天……"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"유통기한은 넉넉할 것으로 추정된다.","JPN":"賞味期限はまだ余裕があると思われる。","ENG":"but the expiration date is estimated to be sufficient.","TWN":"不過我想距離有效期限應該還有一段時間。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……어쩐지 입맛이 돌지 않는다. 방주로 돌아가서 섭취하겠다.","JPN":"……どうにも食欲がない。箱舟に帰還してから摂取することにする。","ENG":"...My appetite is gone. I will eat the rest after returning to the Ark.","TWN":"……不知為何沒有胃口，等回到方舟後再進食吧。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"식량 외에도 관리국이 생산한 표준 개인 화기를 발견, 기능 확인 중이다.","JPN":"食料以外にも管理局が生産した標準個人用火器を発見、動作を確認中。","ENG":"Aside from the rations, I found an Administration-issued standard personal firearm. Checking its functionality now.","TWN":"除糧食外，還有發現管理局生產的標準個人武器，功能確認中。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 다니니…… 부전대장이 떠오르는군.","JPN":"こうしていると……副戦隊長を思い出すな。","ENG":"Walking around like this... reminds me of my deputy commander.","TWN":"這樣走著走著……令我想起副戰隊長。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"필요 없어 보이는 잡동사니도 분명 쓸모가 있을 거라며 주워 모았지.","JPN":"不要そうに見えるガラクタでも、きっと使い道があると言って収集していた。","ENG":"She had picked up useless-looking trash, saying that they would be useful one day.","TWN":"明明看起來沒用的雜物，她也要收集起來，說什麼以後一定會用到。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"희한하게도 그 잡동사니들은 어떤 식으로든 사용되었다.","JPN":"不思議なことに、収集したガラクタは何かしらに利用された。","ENG":"Oddly enough, she did find ways to utilize that junk.","TWN":"更厲害的是，之後還真的可以廢物利用。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"부전대장이 다시 도움을 주었군. 교훈 삼아 모두 챙겨가겠다.","JPN":"副戦隊長にはまた助けられたな。あれを教訓としてすべて回収するとしよう。","ENG":"She has been of assistance once again. All of these will serve as valuable lessons for me to learn.","TWN":"副戰隊長又幫上忙了呢，就當學個教訓，全都帶走吧。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"두 번째 함선에서의 물자 보급을 마쳤다. 소량의 이터니움을 확보해 다행이다.","JPN":"二隻目の艦船での物資の回収を終了。幸い少量のエタニウムを確保できた。","ENG":"I have finished my supply rounds for the second ship. I was lucky enough to secure a bit of Eternium.","TWN":"第二艘艦船巡視完畢，幸好有獲得少量的永恆之金。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"현재, 이동 중 발견한 기갑 병기를 점검하는 중이다.","JPN":"現在、移動中に発見した機甲兵器を点検している。","ENG":"Currently, I am checking some armored vehicles I discovered on my way back.","TWN":"目前正在查看我在移動中發現的裝甲兵器。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"가급적이면…… 사용할 필요가 없길 바라지만.","JPN":"できれば……これを使うことがないと良いが。","ENG":"If possible... I hope there would be no use for it.","TWN":"我只希望……不要有任何需要用到它的突發狀況。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"현재 인근에 방치된 기갑 병기들의 점검을 마치고 세 번째 함선으로 이동…….","JPN":"現在近隣に放置されていた機甲兵器の点検を終了し、三隻目の艦船に移動中……","ENG":"After checking the abandoned armored vehicles nearby, I am heading toward the third ship–","TWN":"擱置在附近的裝甲兵器已經檢查完畢，前往第三艘艦船中……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"포격……? 방주 쪽인가?","JPN":"砲撃……？　箱舟方面か？","ENG":"A bombardment...? Is it coming from near the Ark?","TWN":"爆炸聲……？是在方舟那邊嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"메이즈 전대, 전투를 개시한다!","JPN":"メイズ戦隊、戦闘を開始する！","ENG":"Maze Division, commencing combat!","TWN":"梅茲戰隊，開始戰鬥！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"방주를 공격해 오는 침식체 군집이 날로 늘고 있다.","JPN":"箱舟を攻撃してくる侵食体の群れが日に日に増えてきている。","ENG":"The horde of C.O.s attacking the Ark is growing by the day.","TWN":"攻擊方舟的侵蝕體數量日漸加增。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이상 현상이 우려되므로, 상황이 진정되는 즉시 원인 파악에 나설 예정이다.","JPN":"異常現象発生が懸念されるため、状況が落ち着き次第、即時原因の把握を開始する予定だ。","ENG":"This abnormal phenomenon is concerning, and I am planning to identify the cause after the situation has stabilized.","TWN":"我擔心會有什麼異狀，等情況穩定下來後，就要立刻外出確認原因。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"현재로서는 이 일대를 요새화하는 것이 안전하리라고 판단된다.","JPN":"現時点ではここ一帯を要塞化することがもっとも安全であると判断される。","ENG":"As of now, I assume that it is safe to fortify this area.","TWN":"就現況而言，將這附近一帶要塞化才是安全的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……그 때까지, 다들 조금만 기다려다오.","JPN":"……完成するまで、少し待っていてくれ。","ENG":"...Until then, just wait a little longer.","TWN":"……在那之前，大家再稍等一下。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"후우. 꽤나 힘이 들어가는군.","JPN":"ふう。だいぶ骨の折れる作業だ。","ENG":"Whew, this is harder than it looks.","TWN":"呼，沒想到還蠻辛苦的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"버려진 함선과 주변 암석들을 이용해 요새를 만드는 중이다.","JPN":"捨てられた艦船と周辺の岩石を利用して要塞を築いている。","ENG":"I am making a fortress out of the abandoned ships and rocks around me.","TWN":"我正在利用廢棄的艦船和周圍的岩石打造要塞。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"생각보다…… 힘을 많이 소모해서…….","JPN":"思ったより……力の消耗が激しく……","ENG":"I have used up... more energy than I anticipated...","TWN":"比想像中……還費力……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"작전기록 녹음.","JPN":"作戦記録、録音。","ENG":"Operation log.","TWN":"作戰紀錄錄音。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"잠시…… 정신을 잃은 듯하다.","JPN":"しばらく……気を失っていたようだ。","ENG":"I lost... consciousness for a moment.","TWN":"我剛才……似乎暈倒了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"처음 겪는 현상이라 그런지 현기증이…….","JPN":"初めて経験する現象のため、めまいが……","ENG":"It is my first time experiencing this, and feeling a bit dizzy...","TWN":"這是第一次發生這種情況……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……작전기록 녹음.","JPN":"……作戦記録、録音。","ENG":"...Operation log.","TWN":"……作戰紀錄錄音。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이터니움 충전 이후, 현기증이 멎었다.","JPN":"エタニウムをチャージしてから、めまいがおさまった。","ENG":"After charging Eternium, the dizziness has stopped.","TWN":"補充完永恆之金後，頭就不暈了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"정신은 잃었지만…… 지금은 오히려 몸이 한결 개운해진 기분이다.","JPN":"気を失いはしたが……むしろ今は身体が一段と軽くなった気がする。","ENG":"Though I lost consciousness... my body feels rather refreshed.","TWN":"雖然暫時暈了過去……現在身體感覺反而更舒暢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"자기 관리에 소홀한 모습이라니, 대원들을 지휘하는 입장에서 조금 부끄럽군.","JPN":"自己管理を怠るとは、隊員たちを指揮する立場にある者として少々恥ずかしいな。","ENG":"Being oblivious to my own well-being... I am ashamed to call myself the commander of my division.","TWN":"身為指揮隊員的領袖，卻沒能帶頭管理好自己的身體，真是有點羞愧呢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"방주의 벽면에 선을 하나 더 그었다.","JPN":"箱舟の壁面にもう一つ線を引いた。","ENG":"Another line has been engraved into the Ark's wall.","TWN":"方舟牆上的線又再新增一條。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……휴식을 위해, 오늘의 녹음은 이것으로 마친다.","JPN":"……休憩のため、今日の録音はこれにて終了する。","ENG":"...I will end my recording for the day to get some rest.","TWN":"……今天就先錄到這裡，我需要好好休息一下。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"작전…… 기록 녹음.","JPN":"作戦……記録、録音。","ENG":"Oper... ation log.","TWN":"作戰……紀錄錄音。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"기습해 온 도플갱어들을 격퇴하는 데 성공했다.","JPN":"奇襲してきたドッペルゲンガーたちを撃退することに成功した。","ENG":"I managed to defeat the ambushing Doppelgangers.","TWN":"成功擊退來襲的二重身。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만……. 목숨을 끊었어야 했는데, 할 수 없었다.","JPN":"しかし……命を絶っておくべきだったが、できなかった。","ENG":"However... I could not end their lives, even when I had to.","TWN":"只是……應該要斬草除根才對，但我下不了手。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"전우들의 목소리를 흉내내서 애원할 뿐인데도……. 고작 그것뿐인데……","JPN":"戦友たちの声を真似て命乞いしているだけなのに……ただそれだけなのに……","ENG":"Although I know they are mimicking the cries of my comrades... Even if it's only that...","TWN":"雖然它們只是模仿戰友們的聲音在那苦苦哀求……但我還是……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……정정한다. 기록물에 어울리지 않는 감정적인 표현이었다.","JPN":"……訂正する。記録に相応しくない感情的な表現だった。","ENG":"...Correction. I have expressed emotions that are unfit for operation logs.","TWN":"……更正。不能將私人情緒錄到紀錄中。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"녹음 재개. 전투 중 좌측 허벅지에 총상을 입었다.","JPN":"録音再開。戦闘中に左太ももに銃傷を負った。","ENG":"Resuming recording. I have been shot in my left thigh during battle.","TWN":"重新錄音。戰鬥中左大腿內側受到槍傷。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"확보해 둔 구급용 의료품을 이용해 처치한 결과, 현재는 출혈이 멎은 상태다.","JPN":"確保しておいた救急用の医療品を使用して処置したところ、現在は出血が止まっている。","ENG":"As a result of treating the wound with the first aid I had secured, the bleeding has currently stopped.","TWN":"利用取得的急救箱進行處理後，傷口現在已經止住血。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……붕대를 감을 때 발레리가 떠올랐다. 이렇게 갑갑하게 묶는 사람은 처음이라고 했지.","JPN":"……包帯を巻きながら、ヴァレリーを思い出した。こうしてきつく縛る人は初めて見たと言っていたな。","ENG":"...As I was bandaging my wound, Valeriy came to mind. He said he'd never seen someone bandage a wound so tightly.","TWN":"……包紮時我又想起瓦萊里，他說我是第一個把繃帶包得密不透風的人。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"의료품은 특히 부족하다. 당분간 전면전은 회피하겠다.","JPN":"医療品不足が特に激しい。当分全面戦は回避する。","ENG":"Medical supplies are particularly lacking. Any encounters should be avoided for the time being.","TWN":"醫療用品的庫存量嚴重不足，之後必須避開正面交鋒。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"작전기록 녹음.","JPN":"作戦記録、録音。","ENG":"Operation log.","TWN":"作戰紀錄錄音。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"오늘도…… 지원이 오지 않는다.","JPN":"今日も……応援は来ない。","ENG":"No support... today as well.","TWN":"今天……也沒有支援抵達。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"함선 동결 해제는 실패했고, 도플갱어들의 공격은 계속되고 있다.","JPN":"艦船の凍結を解くのには失敗し、ドッペルゲンガーたちからの攻撃も続いている。","ENG":"Disabling the Ark's stasis was failed, and Doppelgangers' attacks continue.","TWN":"艦船解凍失敗，二重身的攻擊依舊。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 분명, 머지 않은 시일 내로 관리국의 지원이 올 것이다.","JPN":"しかしきっと、近いうちに管理局からの応援が来るはずだ。","ENG":"But one thing is certain. The Administration's support will come in the near future.","TWN":"但我相信，管理局的支援一定很快就會抵達的。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그때까지 아무도 잃지 않고 방주를 지키는 것이……","JPN":"それまで誰も死なさずに、箱舟を守ることが……","ENG":"Until then, my sole mission... is to protect the Ark...","TWN":"在那之前，不要再失去任何一個人，保護方舟……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지금 내가 맡은…… 유일한 임무이다.","JPN":"今の私の……唯一の任務である。","ENG":"without losing anyone.","TWN":"是我現在……唯一的任務。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"……맡은, 유일한, 임무, 이다.","JPN":"……私の、唯一の、任務、である。","ENG":"...protect the Ark, without, losing anyone.","TWN":"……唯一，的，任務。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_08"},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이걸로 마지막인가……. 이제 겨우 전부 옮겨 적었군.","JPN":"これで最後か……やっとすべて文字に起こし終えた。","ENG":"Is this is the last of them...? I finally transcribed all of them.","TWN":"這就是最後了嗎……終於都抄錄完畢。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"류드밀라, 출항 준비 끝났어.","JPN":"リュドミラ、出航の準備は終わったわ。","ENG":"Lyudmila, we're all set for departure.","TWN":"盧德米拉，可以準備出航了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그렇군. 금방 가도록 하지.","JPN":"そうか。すぐに向かう。","ENG":"I see. I will be out right away.","TWN":"好，我等下就過去。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"또 녹음 중이었나 보네. 습관이란 무서워.","JPN":"また録音していたの。習慣って恐ろしいものね。","ENG":"Were you recording yourself again? Guess old habits die hard.","TWN":"你又在錄音嗎？習慣真是可怕。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"아니. 이전 기록들을 확인 중이었다.","JPN":"いや、これまでの記録を確認していたところだ。","ENG":"No. I was checking my previous recordings.","TWN":"不是，我在確認以前的錄音。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그 많은 걸 전부?","JPN":"その大量のものを全部？","ENG":"All of them?","TWN":"很多欸？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"가급적이면 더 알고 싶었어. <color=#ffd34c>나</color>에 대해서.","JPN":"できればもっと知りたかったんだ。<color=#ffd34c>自分</color>について。","ENG":"I wanted to know more about <color=#ffd34c>me</color> as much as possible.","TWN":"因為，我想多知道一點關於<color=#ffd34c>我</color>的事。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흐음……. 꽤 철학적인 이야기네.","JPN":"ふうん……かなり哲学的な話ね。","ENG":"Hmm... That's a rather philosophical, don't you think?","TWN":"嗯……有點哲學的發言。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그렇게까지 진지한 고찰은 아니다만.","JPN":"そこまで真面目な考察ではないが。","ENG":"It is not a serious contemplation.","TWN":"是沒到那麼誇張的程度。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그래서, 이번 목적지는 어딘가?","JPN":"それで、今回はどこに向かうんだ？","ENG":"So, where are we headed to this time?","TWN":"所以這次的目的地是哪裡？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"로터스야. 관리국 쪽 일감을 처리한 다음에 본대는 방주를 확인하러 가야 할 것 같아.","JPN":"ロータスよ。管理局からの依頼を済ませた後、本隊は箱舟を確認しに行く。","ENG":"Lotus. After we take care of the Administration's request, the main division is going to have to check up on the Ark.","TWN":"洛德斯，處理完管理局的事後，本隊必須去確認一下方舟。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"관리자님께 들은 대로군. 별동대를 선발해 둬야겠어.","JPN":"管理者様から聞いたとおりだな。別動隊を選抜しておかなければ。","ENG":"Just as I heard from the Administrator. I should select a detached force beforehand.","TWN":"和管理者說的一樣。必須分出另一支隊伍單獨行動。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그건 애들 있는 데서 정해.","JPN":"それは子どもたちが見ている前で決めて。","ENG":"Let's do that with everyone present.","TWN":"這等大家都在的時候再決定吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"다들 내색 안 해도 현실세계 공기가 좋은 모양이니까.","JPN":"みんな表に出してはいないけど、現実世界の空気の方が良いみたいだし。","ENG":"Even though no one really says it, they seem to like the fresh air in the Normalside.","TWN":"雖然大家沒有表現出來，但應該還是比較喜歡現實世界的空氣吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음. 이면세계 공기를 좋아할 이유는 없으니 말이다.","JPN":"うむ。裏世界の空気を好む理由はないからな。","ENG":"Mm. They have no reason to like the air in the Counterside.","TWN":"嗯，沒有理由喜歡異界的空氣吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"다들 고마워하고 있어, 류드밀라.","JPN":"みんな感謝しているわよ、リュドミラ。","ENG":"Everyone's grateful to you, Lyudmila.","TWN":"大家都很感謝你，盧德米拉。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……매번 말하지만 나는 전우로서, 그리고 상관으로서 할 일을 했을 뿐이다.","JPN":"……毎回言っているが、私は戦友として、そして上官としてやるべきことをやったまでだ。","ENG":"...I say this all the time, but as their comrade and superior, I simply did what needed to be done.","TWN":"……我說過了，我只是做了我身為戰友，身為長官應該做的事而已。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그러니 고마워할 필요는 없어.","JPN":"だから、感謝することはない。","ENG":"So there is no thank me.","TWN":"不需要感謝我。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"참 앞뒤로 꽉 막혔다니까, 우리 전대장님은.","JPN":"本当に頑固よね、うちの戦隊長は。","ENG":"Our commander can be real stuck-up sometimes.","TWN":"我們戰隊長真的是很一板一眼呢。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"준비하고 함교로 와. 애들 너무 오래 기다리게 하지 말고.","JPN":"用意ができたら艦橋に来て。子どもたちをあんまり待たせないようにね。","ENG":"Get ready and meet us at the bridge. And don't make us wait for too long.","TWN":"準備好就過來艦橋這裡，別讓大家等太久。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"작전기록 녹음.","JPN":"作戦記録、録音。","ENG":"Operation log.","TWN":"作戰紀錄錄音。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"기항지에서 부대 정비를 마친 뒤, 현재 출항을 서두르는 중이다.","JPN":"寄港地にて部隊を整備し、現在出航を急いでいる。","ENG":"After completing my troop's maintenance at the port of call, we are now rushing to depart.","TWN":"在中繼站重新整頓好部隊後，現在正準備要出航。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"피와 죽음 사이에서 싸우는 것은 고통이지만……","JPN":"血しぶきと死臭漂う戦場は苦痛だが……","ENG":"Fighting between blood and death is excruciating...","TWN":"雖然在血和死亡之中戰鬥很痛苦……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지금 나와 함께하는 이들 사이에서 싸우는 것은.","JPN":"今私のそばにいてくれる者たちと共に戦えるのは。","ENG":"but to do so in the company of my comrades...","TWN":"但現在能夠和大家一起作戰，"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내게 과분한 영광이다.","JPN":"見に余る光栄だ。","ENG":"it is an unmerited honor for me.","TWN":"對我而言是莫大的榮耀。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이제까지처럼, 앞으로도 영원히.","JPN":"これまでも、これからも永遠に。","ENG":"As it has been, and as it will be.","TWN":"以前是，現在是，未來也是。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이상.","JPN":"以上。","ENG":"Over and out.","TWN":"以上。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};